-- Migración 004: Hackatones reales — Devpost + Devfolio (batch Mar 2026)
-- Ejecutar en Supabase Dashboard → SQL Editor

ON CONFLICT (id) DO UPDATE SET
  title        = EXCLUDED.title,
  prize_pool   = EXCLUDED.prize_pool,
  tags         = EXCLUDED.tags,
  deadline     = EXCLUDED.deadline,
  match_score  = EXCLUDED.match_score,
  source_url   = EXCLUDED.source_url,
  last_seen_at = NOW(),
  updated_at   = NOW();

-- Total: 72 hackatones
SELECT source, count(*) FROM active_hackathons GROUP BY source ORDER BY count DESC;